mapper.select:
SELECT
       d.id AS diary_id
     , d.created_at
  FROM diary d
 WHERE d.user_id = #{userId}
   AND d.forest_id = #{forestId}
   AND d.created_at BETWEEN #{startDateTime} AND #{endDateTime}

SELECT d.id AS diary_id , d.content , d.created_at , u.id AS user_id , u.nickname , de.emotion AS emotion_name FROM diary d JOIN user u ON d.user_id = u.id JOIN forest f ON d.forest_id = f.id JOIN shared_forest sf ON f.id = sf.forest_id JOIN diary_emotion de ON d.id = de.diary_id WHERE d.id IN
#{id}
AND sf.user_id = #{userId}
